    }


    render() {


        var header = "Loading ..."
        var content = []
        var rightContent = []
        var leftContent = []




        if (this.state.addEmployee || this.state.editEmployee) {
            var tempContent = []

            if (this.state.addEmployee) {
                tempContent.push(<div style={{fontSize: '18px'}}>Add Employee<hr></hr></div>)
            }

            if (this.state.editEmployee) {
                tempContent.push(<div>Edit Employee<hr></hr></div>)
            }

            //firstname = "", lastname = "", email = "", employeeid = "", startdate = "", enddate = "", studenttype = ""

            const studentOptions = [
                {label: 'NP', value: 'NP'},
                {label: 'Dental', value: 'Dental'},
                {label: 'Med', value: 'Med'}
              ]



            var addPanel = <table>
                <tr>
                    <td>First Name: </td>
                    <td style={{width: '300px'}}><input type="text" style={{width: '300px'}} onChange={event => this.updateParameter(event, 'firstname')} value={this.state.firstname}></input></td>
                </tr>
                <tr>
                    <td>Last Name: </td>
                    <td><input type="text" style={{width: '300px'}}  onChange={event => this.updateParameter(event, 'lastname')} value={this.state.lastname}></input></td>
                </tr>
                <tr>
                    <td>Email: </td>
                    <td><input type="text" style={{width: '300px'}}  onChange={event => this.updateParameter(event, 'email')} value={this.state.email}></input></td>
                </tr>
                <tr>
                    <td>Employee ID: </td>
                    <td><input type="text" style={{width: '300px'}}  onChange={event => this.updateParameter(event, 'employeeid')} value={this.state.employeeid}></input></td>
                </tr>
                <tr>
                    <td>Start Date: </td>
                    <td><DatePicker 
                        value={this.state.startdate}
                        onChange={dateArray => {const d = new Date(dateArray).toLocaleDateString('fr-FR');this.updateParameterDate(d, 'startdate')}}
                        plugins={[<DatePanel />]}
                        multiple={false}
                        format="MM/DD/YYYY"
                    /></td>
                </tr>
                <tr>
                    <td>End Date: </td>
                    <td>
                        <DatePicker 
                        value={this.state.enddate}
                        onChange={dateArray => {const d = new Date(dateArray).toLocaleDateString('fr-FR');this.updateParameterDate(d, 'enddate')}}
                        plugins={[<DatePanel />]}
                        multiple={false}
                        format="MM/DD/YYYY"
                        />
                    </td>
                </tr>
                <tr>
                    <td>Student Type: </td>
                    <td>
                        <Select
                        value={{label: this.state.studenttype, value: this.state.studenttype}}
                        name="studenttype"
                        options={studentOptions}
                        className="basic-multi-select"
                        classNamePrefix="select"
                        onChange={event => this.updateParameterSelect(event, 'studenttype')}
                        />
                    </td>
                </tr>
            </table>




              tempContent.push(addPanel)




            tempContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleCancelAddEditEmployee()}  id="cancelEmployee" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Cancel</button>&nbsp;&nbsp;<button onClick={() => this.handleAddEditEmployeeSubmit()}  id="addEmployee" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "green" }}>Confirm</button></div>)


            rightContent.push(<div style={{marginTop: "20px", marginBottom: "20px", borderStyle:"solid",borderColor:"coral",padding:"10px"}}>{tempContent}</div>)
        }


        if (this.state.screen === 1) {


            var employeeResult = this.state.employeeResult

            //for (var index in roomResults) {

            var resultTable = [] 

            resultTable.push(<tr><td>First Name</td><td>Last Name</td><td>Email</td><td>Start Date</td><td>End Date</td><td>Student Type</td><td></td><td></td></tr>)

            employeeResult.map(empResult => {
                //var roomResult = roomResults[index]



                resultTable.push(<tr><td>{empResult.first_name}</td><td>{empResult.last_name}</td><td>{empResult.email}</td><td>{empResult.start_date}</td><td>{empResult.end_date}</td><td>{empResult.student_type}</td><td><button onClick={() => this.handleEditEmployee(empResult)}  id={"editEmployee_" + empResult.id} style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Edit</button></td><td><button onClick={() => this.handleDeleteEmployee(empResult)}  id={"deleteEmployee_" + empResult.id} style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Delete</button></td></tr>)

                /*
                var leftContent2 = []
                var rightContent2 = []

